import React, { useState, useContext } from "react";
import Input from "../../shared/components/FormElements/Input";
import Button from "../../shared/components/FormElements/Button";
import { VALIDATOR_EMAIL, VALIDATOR_MINLENGTH, VALIDATOR_REQUIRE } from "../../shared/components/util/validators";
import { useForm } from "../../shared/components/hooks/form-hook";

import ImageUpload from "../../shared/components/FormElements/ImageUpload";
import ErrorModal from '../../shared/components/UIElements/ErrorModal'
import LoadingSpinner from '../../shared/components/UIElements/LoadingSpinner';
import { AuthContext } from "../../shared/components/context/auth-context";
import { useHttpClient } from "../../shared/components/hooks/http-hook";

import './Auth.css';
import Card from "../../shared/components/UIElements/Card";

const Auth = () => {
    const auth = useContext(AuthContext);
    const { isLoading, error, sendRequest, clearError } = useHttpClient();

    const [isLoginMode, setIsLoginMode] = useState(true);
    const [formState, inputHandler, setFormData] = useForm({
        email: {
            value: '',
            isValid: false
        },
        password: {
            value: '',
            isValid: false
        }
    }, false);

    const switchModeHandler = () => {
        if (!isLoginMode) {
            setFormData({
                ...formState.inputs,
                name: undefined,
                image: undefined
            }, 
            formState.inputs.email.isValid && formState.inputs.password.isValid);
        } else {
            setFormData({
                ...formState.inputs,
                name: {
                    value:'',
                    isValid: false
                },
                image: {
                    value: null,
                    isValid: false
                }
            }, false);
        }

        setIsLoginMode(prevMode => !prevMode);
    };

    const authSubmitHandler = async event => {
  event.preventDefault();

  console.log(formState.inputs);

  if (isLoginMode) {
    try {
      const responseData = await sendRequest(
        'http://localhost:5000/api/users/login',
        'POST',
        JSON.stringify({
          email: formState.inputs.email.value,
          password: formState.inputs.password.value
        }),
        { 'Content-Type': 'application/json' }
      );

      auth.login(responseData.user.id);   // ✅ correct

    } catch (err) {}
  } else {
    try {
      const formData = new FormData();
      formData.append('name', formState.inputs.name.value);
      formData.append('email', formState.inputs.email.value);
      formData.append('password', formState.inputs.password.value);
      formData.append('image', formState.inputs.image.value); 

      const responseData = await sendRequest(
        'http://localhost:5000/api/users/signup',
        'POST',
        formData
         );

      auth.login(responseData.user.id);   // ✅ FIXED HERE

    } catch (err) {}
  }
};

    return (
    <React.Fragment>
        <ErrorModal error={error} onClear={clearError} />
    <Card className="authentication">
        {isLoading && <LoadingSpinner asOverlay />}
        <h2>Login Required</h2>
        <hr />
        <form onSubmit={authSubmitHandler}>
            {!isLoginMode && 
            <Input 
            element="input"
            id="name" 
            type="text" 
            label="Your Name" 
            validators={[VALIDATOR_REQUIRE()]}
            errorText="please enter a name."
            onInput={inputHandler}
            />}
            {!isLoginMode && <ImageUpload center id="image" onInput={inputHandler} />}
            <Input 
            element="input" 
            id="email" 
            label="E-mail" 
            validators={[VALIDATOR_EMAIL()]}
            errorText="please enter a valid email address." 
            onInput={inputHandler}
            />
            <Input 
            element="input" 
            id="password" 
            label="Password" 
            validators={[VALIDATOR_MINLENGTH(6)]}
            errorText="please enter a valid password, at least 6 characters." 
            onInput={inputHandler}
            />
            
            <Button type="submit" disabled={!formState.isValid}>{isLoginMode ? 'LOGIN' : 'SIGNUP'}</Button>
            <Button type="button" inverse onClick={switchModeHandler}>{isLoginMode ? 'SIGNUP' : 'LOGIN'}</Button>
        </form>
    </Card>;
    </React.Fragment>
    );
};

export default Auth;
